import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctors() {
  const navigate = useNavigate();

  const [search, setSearch] = useState("");

  const doctors = [
    { name: "Dr. John Smith", specialty: "Cardiologist" },
    { name: "Dr. Sarah Lee", specialty: "Dermatologist" },
    { name: "Dr. David Kumar", specialty: "Orthopedic" },
    { name: "Dr. Priya Nair", specialty: "Pediatrician" },
  ];

  const handleViewProfile = (name, specialty) => {
    navigate("/doctorprofile", {
      state: { name, specialty }
    });
  };

  const filteredDoctors = doctors.filter((doc) =>
    doc.name.toLowerCase().includes(search.toLowerCase()) ||
    doc.specialty.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={styles.container}>

      {/* Navbar */}
      <Navbar />

      {/* Search */}
      <div style={styles.searchContainer}>
        <input
          type="text"
          placeholder="Search doctor name or profession..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={styles.searchInput}
        />
      </div>

      {/* Doctor Cards */}
      <div style={styles.cardContainer}>

        {filteredDoctors.length > 0 ? (
          filteredDoctors.map((doc, index) => (
            <div key={index} style={styles.card}>
              
              <img
                src="https://cdn-icons-png.flaticon.com/512/387/387561.png"
                alt={`Dr. ${doc.name}`}
                style={styles.image}
              />

              <h3>{doc.name}</h3>
              <p>{doc.specialty}</p>

              <button
                style={styles.button}
                onClick={() => handleViewProfile(doc.name, doc.specialty)}
              >
                View Profile
              </button>

            </div>
          ))
        ) : (
          <p style={styles.noResult}>No doctors found 😔</p>
        )}

      </div>

      {/* Footer */}
      <Footer />

    </div>
  );
}

export default Doctors;
